    "FOTO DO AUTOR": "https://images.squarespace-cdn.com/content/v1/5cf66fee1ecc9c00013e07ef/a227410f-5522-4fca-81ba-52fcbcc3defe/Rose%2C+Jeneva+2.jpg",
