    "URL DA CAPA": "https://m.media-amazon.com/images/I/71RwZmo1ESL._SY522_.jpg",
    "FOTO DO AUTOR": "https://m.media-amazon.com/images/S/amzn-author-media-prod/rjg6r1e28ms2eb14oj4v76r3de._SY300_CR0%2C0%2C300%2C300_.jpg",
    "LINK DE PARCEIRO": "https://amzn.to/48jNDrp",
