    "FOTO DO AUTOR": "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQfgJUHEymPZArUrBtQtTpy0x8erC6Tz4xE2Q&s",
    "LINK DE PARCEIRO": "4.5",
